/**
 * Side-by-Side Diff Extension
 *
 * Replaces the default inline diff rendering for the edit tool with a
 * two-column "Previous" (left) / "Now" (right) card layout.
 *
 * The built-in edit tool execution is reused — only the rendering changes.
 *
 * Usage: drop in ~/.pi/agent/extensions/ and /reload
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import {
	createEditToolDefinition,
	renderDiff,
} from "@mariozechner/pi-coding-agent";
import { Box, Container, Spacer, Text } from "@mariozechner/pi-tui";
import { Type } from "@sinclair/typebox";
import { visibleWidth, truncateToWidth } from "@mariozechner/pi-tui";

// ---------------------------------------------------------------------------
// Side-by-side diff component
// ---------------------------------------------------------------------------

class SideBySideDiff extends Container {
	private oldLines: string[];
	private newLines: string[];
	private cachedWidth?: number;
	private cachedLines?: string[];

	constructor(
		private diffText: string,
		private theme: any,
	) {
		super();
		const { oldLines, newLines } = this.parseDiff(diffText);
		this.oldLines = oldLines;
		this.newLines = newLines;
	}

	/**
	 * Parse the unified diff format (generated by generateDiffString) into
	 * separate old and new line arrays.
	 *
	 * Format per line:  "<prefix><lineNum> <content>"
	 *   prefix: "+" (added), "-" (removed), " " (context), "  " + "..." (ellipsis)
	 */
	private parseDiff(diffText: string): { oldLines: string[]; newLines: string[] } {
		const oldLines: string[] = [];
		const newLines: string[] = [];
		let oldLineNum = 0;
		let newLineNum = 0;

		// First pass: determine max line numbers for alignment
		const rawLines = diffText.split("\n");
		for (const line of rawLines) {
			const match = line.match(/^([+\-\s])\s*(\d*)\s(.*)$/);
			if (!match) {
				// ellipsis or other
				const isEllipsis = line.match(/^\s+\.\.\./);
				if (isEllipsis) {
					oldLines.push("...");
					newLines.push("...");
				}
				continue;
			}
			const [, prefix, lineNumStr, content] = match;
			const lineNum = parseInt(lineNumStr, 10) || 0;

			if (prefix === "-") {
				oldLineNum = lineNum;
				oldLines.push(`${lineNum} ${content}`);
			} else if (prefix === "+") {
				newLineNum = lineNum;
				newLines.push(`${lineNum} ${content}`);
			} else {
				// context line
				oldLineNum = lineNum;
				newLineNum = lineNum;
				oldLines.push(`${lineNum} ${content}`);
				newLines.push(`${lineNum} ${content}`);
			}
		}

		return { oldLines, newLines };
	}

	override render(width: number): string[] {
		if (this.cachedLines && this.cachedWidth === width) {
			return this.cachedLines;
		}

		const midGap = 3; // " │ " separator
		const halfWidth = Math.floor((width - midGap) / 2);
		const leftWidth = halfWidth;
		const rightWidth = width - leftWidth - midGap;

		if (leftWidth < 10 || rightWidth < 10) {
			// Terminal too narrow — fall back to inline diff
			return super.render(width);
		}

		// Headers
		const leftHeader = this.theme.fg("toolDiffRemoved", this.theme.bold(" Previous"));
		const rightHeader = this.theme.fg("toolDiffAdded", this.theme.bold(" Now"));
		const separator = this.theme.fg("border", "│");

		const lines: string[] = [];

		// Header row
		const leftHeaderText = padOrTruncate(leftHeader, leftWidth);
		const rightHeaderText = padOrTruncate(rightHeader, rightWidth);
		lines.push(leftHeaderText + this.theme.fg("dim", " ") + separator + this.theme.fg("dim", " ") + rightHeaderText);

		// Separator line
		lines.push(this.theme.fg("border", "─".repeat(leftWidth) + "─┼─" + "─".repeat(rightWidth)));

		// Interleave old and new lines side-by-side
		const maxLines = Math.max(this.oldLines.length, this.newLines.length);
		const rawDiffLines = this.diffText.split("\n");

		// Track position in old/new arrays
		let oldIdx = 0;
		let newIdx = 0;

		// Parse again but now render side-by-side with proper colors
		for (const rawLine of rawDiffLines) {
			const match = rawLine.match(/^([+\-\s])\s*(\d*)\s(.*)$/);
			if (!match) {
				// Ellipsis or other — render in both columns
				if (rawLine.match(/^\s+\.\.\./)) {
					const ellipsis = this.theme.fg("dim", "...");
					const left = padOrTruncate(ellipsis, leftWidth);
					const right = padOrTruncate(ellipsis, rightWidth);
					lines.push(left + this.theme.fg("dim", " ") + separator + this.theme.fg("dim", " ") + right);
				}
				continue;
			}

			const [, prefix, lineNumStr, content] = match;

			if (prefix === "-") {
				// Removed line: show in left column, empty in right
				const lineNum = lineNumStr;
				const left = this.theme.fg("toolDiffRemoved", `${lineNum} ${content}`);
				const right = "";
				lines.push(
					padOrTruncate(left, leftWidth)
					+ this.theme.fg("dim", " ") + separator + this.theme.fg("dim", " ")
					+ padOrTruncate(right, rightWidth),
				);
			} else if (prefix === "+") {
				// Added line: empty in left, show in right
				const lineNum = lineNumStr;
				const left = "";
				const right = this.theme.fg("toolDiffAdded", `${lineNum} ${content}`);
				lines.push(
					padOrTruncate(left, leftWidth)
					+ this.theme.fg("dim", " ") + separator + this.theme.fg("dim", " ")
					+ padOrTruncate(right, rightWidth),
				);
			} else {
				// Context line: show in both
				const lineNum = lineNumStr;
				const styled = this.theme.fg("toolDiffContext", `${lineNum} ${content}`);
				lines.push(
					padOrTruncate(styled, leftWidth)
					+ this.theme.fg("dim", " ") + separator + this.theme.fg("dim", " ")
					+ padOrTruncate(styled, rightWidth),
				);
			}
		}

		this.cachedWidth = width;
		this.cachedLines = lines;
		return lines;
	}

	override invalidate(): void {
		this.cachedWidth = undefined;
		this.cachedLines = undefined;
		super.invalidate();
	}
}

