// Extension
// ---------------------------------------------------------------------------

const editSchema = Type.Object({
	path: Type.String({ description: "Path to the file to edit" }),
	edits: Type.Array(
		Type.Object({
			oldText: Type.String(),
			newText: Type.String(),
		}),
	),
});

export default function (pi: ExtensionAPI) {
	const builtIn = createEditToolDefinition(process.cwd());

	pi.registerTool({
		name: "edit",
		label: "edit",
		description: builtIn.description,
		promptSnippet: builtIn.promptSnippet,
		promptGuidelines: builtIn.promptGuidelines,
		parameters: editSchema,
		prepareArguments: builtIn.prepareArguments,
		renderShell: "self" as const,

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			return builtIn.execute(toolCallId, params, signal, onUpdate, ctx);
		},

		renderCall(args: any, theme: any, context: any) {
			return builtIn.renderCall!(args, theme, context);
		},

		renderResult(result: any, options: any, theme: any, context: any) {
			const diff = result.details?.diff;

			if (!diff || context.isError) {
				return builtIn.renderResult!(result, options, theme, context);
			}

			const container = new Container();

			// Keep the built-in header (file path + success badge)
			const callHeader = builtIn.renderCall!(context.args, theme, {
				...context,
				expanded: false,
			});
			container.addChild(callHeader);
			container.addChild(new Spacer(1));

			// Side-by-side diff with card backgrounds
			const sideBySide = new SideBySideDiff(diff, theme);
			container.addChild(sideBySide);

			return container;
		},
	});
}

