renderResult(result: any, options: any, theme: any, context: any) {
	// Errors get their own card
	if (context.isError) {
		const errorText = result.content
			?.filter((c: any) => c.type === "text")
			?.map((c: any) => c.text || "")
			?.join("\n") || "Error";
		const container = new Container();
		container.addChild(new Text(theme.fg("toolTitle", theme.bold("edit")), 0, 0));
		container.addChild(new Spacer(1));
		container.addChild(new Text(theme.fg("error", errorText), 1, 0));
		return container;
	}

	// The diff was already shown by renderCall during the preview phase.
	// ToolExecutionComponent stacks both renderCall + renderResult, so
	// return an empty container to avoid duplication.
	return new Container();
},

